{"type":"permission_response","request_id":"perm-1773175685982-ccxakgl","subtype":"success","response":{"updated_input":{"file_path":"/home/ketan/project/flotsam/.claude/worktrees/worktree/chrome-ext/chrome-extension/options/options.js","content":"document.addEventListener("DOMContentLoaded", async () => {
  const form = document.getElementById("settings-form");
  const apiUrlInput = document.getElementById("api-url");
  const jwtTokenInput = document.getElementById("jwt-token");
  const statusDiv = document.getElementById("status");

  // Load saved settings
  const { apiUrl, jwtToken } = await chrome.storage.local.get([
    "apiUrl",
    "jwtToken",
  ]);
  if (apiUrl) apiUrlInput.value = apiUrl;
  if (jwtToken) jwtTokenInput.value = jwtToken;

  form.addEventListener("submit", async (e) => {
    e.preventDefault();

    const url = apiUrlInput.value.trim();
    const token = jwtTokenInput.value.trim();

    if (!url) {
      showStatus("API URL is required", "error");
      return;
    }
    if (!token) {
      showStatus("JWT token is required", "error");
      return;
    }

    try {
      new URL(url);
    } catch {
      showStatus("Invalid URL format", "error");
      return;
    }

    await chrome.storage.local.set({ apiUrl: url, jwtToken: token });
    showStatus("Settings saved!", "success");
  });

  function showStatus(message, type) {
    statusDiv.textContent = message;
    statusDiv.className = type;
    statusDiv.hidden = false;
    setTimeout(() => {
      statusDiv.hidden = true;
    }, 3000);
  }
});
"},"permission_updates":[]}}
